/// Try to match select pattern that represents fabs, -fabs, or similar.
/// Matches: select (fcmp pred X, 0), X, -X for any predicate pred.
/// The key property is that the result is zero iff X is zero, regardless of
/// the predicate or sign. This allows folding fcmp pred select, 0 to fcmp pred X, 0.
static bool matchSelectAsFAbs(Value *V, Value *&X) {
  SelectInst *SI = dyn_cast<SelectInst>(V);
  if (!SI)
    return false;

  Value *Cond = SI->getCondition();
  Value *TrueVal = SI->getTrueValue();
  Value *FalseVal = SI->getFalseValue();

  // Match: select (fcmp pred X, 0), X, -X
  FCmpInst *FCmp = dyn_cast<FCmpInst>(Cond);
  if (!FCmp)
    return false;
  if (!match(FCmp->getOperand(0), m_Value(X)))
    return false;
  if (!match(FCmp->getOperand(1), m_AnyZeroFP()))
    return false;
  if (!match(TrueVal, m_Specific(X)))
    return false;

  // False value should be -X (either fneg X or fsub 0, X)
  if (!match(FalseVal, m_FNeg(m_Specific(X))))
    return false;

  // All predicates are valid: the result is zero iff X is zero.
  // For predicates like OGE/OGT/UGE/UGT, this computes fabs(X).
  // For OLE/OLT/ULE/ULT, this computes -fabs(X).
  // For UEQ/UNE/OEQ/ONE, the pattern still has the zero property.
  return true;
}
