/// Try to match select pattern that selects between X and -X.
/// Matches: select cond, X, -X for any condition.
/// The key property is that both X and -X are zero iff X is zero,
/// so fcmp pred select, 0 can be simplified to fcmp pred X, 0.
static bool matchSelectNegPattern(Value *V, Value *&X) {
  SelectInst *SI = dyn_cast<SelectInst>(V);
  if (!SI)
    return false;

  Value *TrueVal = SI->getTrueValue();
  Value *FalseVal = SI->getFalseValue();

  // Match: select cond, X, -X
  if (!match(TrueVal, m_Value(X)))
    return false;

  // False value should be -X (either fneg X or fsub 0, X)
  if (!match(FalseVal, m_FNeg(m_Specific(X))))
    return false;

  return true;
}

/// Optimize fabs(X) compared with zero.
